    my $left = [$arr->@*[0..$mid - 1]];
    my $right = [$arr->@*[$mid..@$arr - 1]];

    # Recursively sort both halves
    my $left_sorted = merge_sort($left);
    my $right_sorted = merge_sort($right);

    # Merge the two sorted halves
    my $merged = merge($left_sorted, $right_sorted);

    return $merged;
}

# Main program
print "Enter integers separated by spaces (end with 'exit'):\n";

# Read input
my @input;
while (1) {
    chomp(my $line = <STDIN>);
    last if $line eq 'exit';

    # Split input line into integers
    my @numbers = map { $_ = int($_) } split(/\s+/, $line);
    push @input, @numbers;

    # Check for invalid input (non-integer values)
    foreach my $num (@numbers) {
        if (!is_integer($num)) {
            die "Invalid input: non-integer value found.\n";
        }
    }
}

# Sort the array in descending order using merge sort
my $sorted_array = merge_sort(\@input);

# Print the sorted array
print "Sorted array in descending order:\n";
foreach my $num (@$sorted_array) {
    print "$num\n";
}

# Helper function to check if a value is an integer
sub is_integer {
    return ref $_[0] eq 'ARRAY' && grep { $_ eq 'int' } map { $_ eq 'int' ? 1 : 0 } map { $_ } @_;
}
```

### 📌 Notes:
- The `merge` function merges two sorted arrays in descending order.
- The `merge_sort` function recursively divides the array and merges the sorted halves.
- The program gracefully handles invalid inputs (e.g., non-integer values).
